// ══════════════════════════════════════════════════════════════════
// Esperar y Verificar Canción
// Hace polling al endpoint /api/get hasta que la canción esté completa
// ══════════════════════════════════════════════════════════════════

const API_BASE = 'https://suno-api-pskc.onrender.com';
const POLL_INTERVAL_MS = 10000;   // cada 10 segundos
const MAX_ATTEMPTS = 36;          // máximo 6 minutos

// Obtener IDs de la respuesta del generate
const generateResponse = $input.first().json;
const songs = Array.isArray(generateResponse) ? generateResponse : [generateResponse];
const songIds = songs.map(s => s.id).filter(Boolean).join(',');

if (!songIds) {
  throw new Error('No se encontraron IDs de canciones en la respuesta: ' + JSON.stringify(generateResponse));
}

console.log(`[CapyMelodys] Esperando canciones: ${songIds}`);

// Recuperar datos del estilo (de nodo anterior en el workflow)
const configJson = $('🎨 Determinar Estilo del Día').first().json;

// ── Polling loop ───────────────────────────────────────────────────
let completedSong = null;

for (let attempt = 1; attempt <= MAX_ATTEMPTS; attempt++) {
  // Esperar antes de consultar
  await new Promise(resolve => setTimeout(resolve, POLL_INTERVAL_MS));

  console.log(`[CapyMelodys] Intento ${attempt}/${MAX_ATTEMPTS} – verificando ${songIds}`);

  let statusSongs;
  try {
    const res = await fetch(`${API_BASE}/api/get?ids=${songIds}`);
    if (!res.ok) {
      console.warn(`[CapyMelodys] HTTP ${res.status} al verificar – reintentando...`);
      continue;
    }
    statusSongs = await res.json();
  } catch (fetchErr) {
    console.warn(`[CapyMelodys] Fetch error: ${fetchErr.message} – reintentando...`);
    continue;
  }

  if (!Array.isArray(statusSongs) || statusSongs.length === 0) {
    console.warn('[CapyMelodys] Respuesta inesperada del servidor');
    continue;
  }

  const statuses = statusSongs.map(s => s.status);
  console.log(`[CapyMelodys] Estados: ${statuses.join(', ')}`);

  // Error en alguna canción
  const failed = statusSongs.find(s => s.status === 'error');
  if (failed) {
    throw new Error('Error en la generación: ' + (failed.error_message || 'desconocido'));
  }

  // Al menos una completa con audio_url
  const done = statusSongs.find(s =>
    (s.status === 'complete' || s.status === 'streaming') && s.audio_url
  );

  if (done) {
    completedSong = done;
    console.log(`[CapyMelodys] ✅ Canción lista: ${done.id}`);
    console.log(`[CapyMelodys] audio_url: ${done.audio_url}`);
    console.log(`[CapyMelodys] image_url: ${done.image_url}`);
    break;
  }
}

if (!completedSong) {
  throw new Error(`Timeout: la canción no se completó en ${MAX_ATTEMPTS * POLL_INTERVAL_MS / 1000} segundos`);
}

// ── Retornar datos para los nodos siguientes ───────────────────────
return [{
  json: {
    song_id:      completedSong.id,
    audio_url:    completedSong.audio_url,
    image_url:    completedSong.image_url || '',
    lyric:        completedSong.lyric || '',
    duration:     completedSong.duration || '',
    // Datos para YouTube (copiados del nodo de estilo)
    youtubeTitle: configJson.youtubeTitle,
    description:  configJson.description,
    tags:         configJson.tags,
    songTitle:    configJson.title,
  }
}];
